trigger.body:
existing_count NUMBER;

BEGIN

  IF AD_isTriggerEnabled()='N' THEN RETURN;
  END IF;

	IF INSERTING OR UPDATING THEN

		SELECT COUNT(*) INTO existing_count
		FROM sccrt_concepts
		WHERE type = :NEW.type
		AND Ssccr_Processor_Banck_ID = :NEW.Ssccr_Processor_Banck_ID
		AND sccrt_concepts_id <> :NEW.sccrt_concepts_id;

        IF existing_count > 0 THEN
            RAISE_APPLICATION_ERROR(-20000, '@No se permite duplicar el tipo de Retencion@');
        END IF;

    END IF;


  END SCCRT_CONCEPTS_TYPE_TRG
